function t(key){
  return (I18N[_lang]&&I18N[_lang][key])||I18N.es[key]||key;
}

function applyI18n(){
  document.documentElement.lang=_lang;
  document.querySelectorAll('[data-i18n]').forEach(el=>{
    const key=el.getAttribute('data-i18n');
    const val=t(key);
    // Permitir HTML embebido solo en claves marcadas (contienen <strong>)
    if(val.includes('<strong')||val.includes('<em')){el.innerHTML=val;}else{el.textContent=val;}
  });
  document.querySelectorAll('[data-i18n-ph]').forEach(el=>{
    el.setAttribute('placeholder',t(el.getAttribute('data-i18n-ph')));
  });
}

function setLang(lang){
  _lang=lang;
  document.getElementById('lang-es').classList.toggle('active',lang==='es');
  document.getElementById('lang-en').classList.toggle('active',lang==='en');
  applyI18n();
  // Re-renderizar contenido dinámico del Modo Aprendizaje si está activo
  if(document.getElementById('es0')?.classList.contains('act')){
    renderProblemList();
  }
  if(S.edu.problemId&&document.getElementById('edu-problem-detail')?.innerHTML.trim()){
    renderProblemDetail();
  }
  if(S.edu.caseId&&document.getElementById('edu-brief-block')?.innerHTML.trim()){
    renderEduBrief(EDU_CASES[S.edu.caseId]);
  }
  if(S.edu.pretestSubmitted===false){
    renderQuiz('edu-pretest-qs',S.edu.pretest,'pre');
  }
  if(S.edu.analysisSnapshot){
    renderEduResults();
  }
  if(document.getElementById('es8')?.classList.contains('act')&&S.edu.analysisSnapshot){
    renderReportSummary();
  }
}

function initI18n(){
  applyI18n();
}

